     7→#define assert(message, test) do { if (!(test)) { Shutdown(); printf(message); return 1; } } while (0)
     8→
     9→int main()
    10→{
    11→    int fd;
    12→    int success;
    13→    char writeBuf[4];
    14→    char readBuf2[9];
    15→    writeBuf[0] = 'S';
    16→    writeBuf[1] = 'S';
    17→    writeBuf[2] = 'S';
    18→    writeBuf[3] = 'S';
    19→
    20→    char files[17] = "qwertyuioplkjhgf";
    21→
    22→    fd = Create("a");
    23→    assert("Failed simple open a\n", fd == 0);
    24→    printf("fd: %i\n", fd);
    25→    Create("b");
    26→
    27→
    28→    success = MkDir("a");
    29→    assert("Failed Mkdir on existing file\n", success == ERROR);
    30→
    31→    success = MkDir("aa");
    32→    assert("Failed simple mkdir\n", success == 0);
    33→
    34→    success = Unlink("a");
    35→    assert("Failed unlink\n", success == 0);
    36→    Close(0);
    37→
    38→    fd = Create("b");
    39→    printf("fd: %i\n", fd);
    40→    assert("Make after unlink failed\n", fd == 0);
    41→
    42→    success = Write(0, writeBuf, 4);
    43→    assert("Write to file failed\n", success == 4);
    44→
    45→    Seek(0, 0, 0);
    46→
    47→    success = Read(0, readBuf2, 4);
    48→    assert("Read failed\n", success == 4);
    49→    assert("Wrong string in read buffer\n", strncmp(readBuf2, "SSSS", 4) == 0);
    50→
    51→    success = Write(0, writeBuf, 4);
    52→    assert("Write to file failed\n", success == 4);
    53→
    54→    Seek(0, 0, 0);
    55→
    56→    success = Read(0, readBuf2, 8);
    57→    assert("Wrong string in read buffer\n", strncmp(readBuf2, "SSSSSSSS", 8) == 0);
    58→
    59→    int i;
    60→    for (i = 0; i < 14; i++) {
    61→        fd = Create((char *)&files[i]);
    62→        printf("creating %s at index %i, resulting in fd %i\n", (char *)&files[i], i, fd);
    63→        assert("Random file not created correctly\n", fd == i + 2);
    64→    }
    65→
    66→    fd = Create((char *)&files[14]);
    67→    assert("Tried to create a file with 16 files open\n", fd == -1);
    68→
    69→    Seek(0, 0, 0);
    70→
    71→    success = Read(0, readBuf2, 4);
    72→    assert("Read failed\n", success == 4);
    73→    assert("Wrong string in read buffer\n", strncmp(readBuf2, "SSSS", 4) == 0);
    74→
    75→	printf("All tests passed\n");
    76→	return Shutdown();
    77→}
