    14→#include <comp421/filesystem.h>
    15→#include <comp421/iolib.h>
    16→#include <comp421/yalnix.h>
    17→#include <stdio.h>
    18→#include <stdlib.h>
    19→#include <string.h>
    20→
    21→#define assert(message, test) do { if (!(test)) { Shutdown(); printf(message); return 1; } } while (0)
    22→#define SIZE 8 * SECTORSIZE
    23→
    24→int main()
    25→{
    26→	// Set up for the tests
    27→	fprintf(stderr, "Set up for the read tests\n");
    28→
    29→	int fd, ret, i, j;
    30→	char buf[SIZE + 1], ref[SIZE], zero[SIZE], fff[SIZE];
    31→	struct Stat mystat;
    32→
    33→	// Fill buf with 'A' and ref with 'B'
    34→	for(i = 0 ; i < SIZE ; i++) {
    35→		buf[i] = 'A';
    36→		ref[i] = 'B'; // used later
    37→		zero[i] = '\0'; //used later
    38→		fff[i] = 'F'; //used later
    39→	}
    40→
    41→	fd = Create("a");
    42→
    43→	for(i = 0 ; i < 5 ; i++) {	// Indirect block write
    44→		for(j = 0 ; j < SIZE ; j++)
    45→			buf[j]++;
    46→		ret = Write(fd, buf, SIZE);
    47→		assert("Write position not advancing correctly in indirect block writes\n", ret == SIZE);
    48→	}
    49→
    50→	// Seeking to the end of those 5 blocks, skipping a block, and then writing another block
    51→	ret = Seek(fd, 0, SEEK_END);
    52→        printf("Result for Seek end: %d\n", ret);
    53→	assert("Seek end not working correctly\n", ret == SIZE * 5);
    54→
    55→	ret = Seek(fd, SIZE, SEEK_CUR);
    56→	assert("Seek not allowed to seek past end of file?\n", ret == SIZE * 6);
    57→
    58→	ret = Write(fd, buf, SIZE);
    59→	assert("Write position not advancing correctly after seeking past end of file\n", ret == SIZE);
    60→
    61→	ret = Seek(fd, 0, SEEK_END);
    62→        printf("Seek end: %d\n", ret);
    63→	assert("Seek set not working correctly after skipping\n", ret == SIZE * 7);
    64→
    65→	ret = Seek(fd, 0, SEEK_SET);
    66→	assert("Seek set not working correctly\n", ret == 0);
    67→
    68→	ret = Seek(fd, -1, SEEK_SET);
    69→	assert("Seek set allowed to seek before beginning of file\n", ret == ERROR);
    70→
    71→	ret = Seek(fd, -1, SEEK_CUR);
    72→	assert("Seek cur allowed to seek before beginning of file\n", ret == ERROR);
    73→	Close(fd);
    74→
    75→	// Test stat of a
    76→	fprintf(stderr, "Test stat of a\n");
    77→	ret = Stat("a", &mystat);
    78→	fprintf(stderr, "Stat a: [%d], inode=%d, type=%d, size=%d, nlink=%d\n", ret, mystat.inum, mystat.type, mystat.size, mystat.nlink);
    79→	assert("Stats failed on a", ret == 0 && mystat.inum == 47 && mystat.type == INODE_REGULAR && mystat.size == SIZE * 7 && mystat.nlink == 1);
    80→
    81→	// Begin read tests on a file
    82→	fprintf(stderr, "Begin read tests on a file\n");
    83→	fd = Open("a");
    84→	ret = Read(fd, buf, 16);
    85→	assert("Read wrong number of bytes: BBB\n", ret == 16);
    86→	buf[16] = 0;
    87→        printf("buf: %s\n", buf);
    88→	assert("Failed read on file: BBB\n", strncmp(buf, "BBBBBBBBBBBBBBBB", 16) == 0);
    89→
    90→	ret = Seek(fd, SIZE, SEEK_SET);
    91→	ret = Read(fd, buf, 16);
    92→	assert("Read wrong number of bytes: CCC\n", ret == 16);
    93→	buf[16] = 0;
    94→	assert("Failed read on file: CCC\n", strncmp(buf, "CCCCCCCCCCCCCCCC", 16) == 0);
    95→
    96→	ret = Seek(fd, SIZE * 2, SEEK_SET);
    97→	ret = Read(fd, buf, 16);
    98→	assert("Read wrong number of bytes: DDD\n", ret == 16);
    99→	buf[16] = 0;
   100→	assert("Failed read on file: DDD\n", strncmp(buf, "DDDDDDDDDDDDDDDD", 16) == 0);
   101→
   102→	ret = Seek(fd, 0, SEEK_SET);
   103→	ret = Read(fd, buf, SIZE);
   104→	assert("Read wrong number of bytes: BBB\n", ret == SIZE);
   105→	assert("Failed read on file: ref\n", strncmp(buf, ref, SIZE) == 0);
   106→
   107→	// Here we're attempting to read the '\0' gap block in the 6th block
   108→	ret = Seek(fd, SIZE * -2, SEEK_END);
   109→	assert("Seeking to wrong place in file: 000\n", ret == SIZE * 5);
   110→	ret = Read(fd, buf, SIZE);
   111→	assert("Read wrong number of bytes: 000\n", ret == SIZE);
   112→	assert("Failed read on file: 000\n", strncmp(buf, zero, SIZE) == 0);
   113→
   114→	// And then we attempt to read the FFF which should be in the 7th block, right past the gap block
   115→	ret = Read(fd, buf, SIZE);
   116→	assert("Read wrong number of bytes: FFF\n", ret == SIZE);
   117→	assert("Failed read on file: FFF\n", strncmp(buf, fff, SIZE) == 0);
   118→
   119→	ret = Seek(fd, 0, SEEK_END);
   120→	ret = Read(fd, buf, SIZE);
   121→	assert("Read wrong number of bytes: seek end\n", ret == 0);
   122→	Close(fd);
   123→
   124→	// Test Reading and writing on directories
   125→	fprintf(stderr, "Test Reading and writing on directories\n");
   126→	fd = Open(".");
   127→	ret = Read(fd, buf, 16);
   128→	assert("Read wrong number of bytes: . dir\n", ret == 16);
   129→	ret = Write(fd, buf, 16);
   130→	assert("Wrote to directory\n", ret == ERROR);
   131→	Close(fd);
   132→
   133→	fd = Open("/");
   134→	ret = Read(fd, buf, 16);
   135→	assert("Read wrong number of bytes: / dir\n", ret == 16);
   136→	ret = Write(fd, buf, 16);
   137→	assert("Wrote to directory\n", ret == ERROR);
   138→	Close(fd);
   139→
   140→	// Null tests
   141→	fprintf(stderr, "null tests\n");
   142→	fd = Open(NULL);
   143→	assert("Opened null file\n", fd == ERROR);
   144→	ret = Read(fd, buf, 16);
   145→	assert("Read null file\n", ret == ERROR);
   146→	ret = Write(fd, buf, 16);
   147→	assert("Wrote null file\n", ret == ERROR);
   148→	ret = Stat(NULL, &mystat);
   149→	assert("Stats on null", ret == ERROR);
   150→	ret = Stat("a", NULL);
   151→	assert("Stats with null stat struct", ret == ERROR);
   152→
   153→	// Test more stat things
   154→	fprintf(stderr, "Test more stat things\n");
   155→	fd = Create("b");
   156→	for(j = 0 ; j < SIZE ; j++)
   157→		buf[j]++;
   158→	ret = Write(fd, buf, 16);
   159→	Close(fd);
   160→	ret = Stat("b", &mystat);
   161→	assert("Stats failed on b", ret == 0 && mystat.inum == 46 && mystat.type == INODE_REGULAR && mystat.size == 16 && mystat.nlink == 1);
   162→
   163→	ret = MkDir("c");
   164→	ret = Stat("c", &mystat);
   165→	assert("Stats failed on c", ret == 0 && mystat.inum == 45 && mystat.type == INODE_DIRECTORY && mystat.size == 64 && mystat.nlink == 2);
   166→
   167→	ret = MkDir("c/d");
   168→	ret = Stat("c/d", &mystat);
   169→	assert("Stats failed on c/d", ret == 0 && mystat.inum == 44 && mystat.type == INODE_DIRECTORY && mystat.size == 64 && mystat.nlink == 2);
   170→
   171→	ret = Stat("f", &mystat);
   172→	assert("Stats failed on f", ret == ERROR);
   173→
   174→	ret = Sync();
   175→	assert("Sync failed", ret == 0);
   176→
   177→	printf("All tests passed\n");
   178→	return Shutdown();
   179→}
