   669→static int resolve_path(const char *path, int cwd_inum, int follow_last,
   670→                        int *parent_out, char *last_name, int *last_len,
   671→                        int symlink_depth) {
   672→    char buf[MAXPATHNAMELEN + 2];
   673→    int pathlen;
   674→
   675→    if (path == NULL || path[0] == '\0') return ERROR;
   676→    if (symlink_depth > MAXSYMLINKS) return ERROR;
   677→
   678→    pathlen = strlen(path);
   679→    if (pathlen >= MAXPATHNAMELEN) return ERROR;
   680→
   681→    /* Copy path to local buffer */
   682→    memcpy(buf, path, pathlen + 1);
   683→
   684→    /* Normalize trailing slash: treat as if "." follows */
   685→    if (pathlen > 0 && buf[pathlen - 1] == '/') {
   686→        if (pathlen + 1 >= MAXPATHNAMELEN) return ERROR;
   687→        buf[pathlen] = '.';
   688→        buf[pathlen + 1] = '\0';
   689→        pathlen++;
   690→    }
   691→
   692→    /* Determine starting inode */
   693→    int cur_inum = (buf[0] == '/') ? ROOTINODE : cwd_inum;
   694→    char *p = buf + (buf[0] == '/' ? 1 : 0);
   695→
   696→    /* Skip leading slashes */
   697→    while (*p == '/') p++;
   698→
   699→    /* If path was just "/" (now normalized to "/.") */
   700→    if (*p == '\0') {
   701→        /* Empty remainder means we resolved to cur_inum */
   702→        if (parent_out) *parent_out = cur_inum;
   703→        if (last_name) {
   704→            last_name[0] = '.';
   705→            if (1 < DIRNAMELEN) last_name[1] = '\0';
   706→        }
   707→        if (last_len) *last_len = 1;
   708→        return cur_inum;
   709→    }
   710→
   711→    while (*p != '\0') {
   712→        /* Skip slashes */
   713→        while (*p == '/') p++;
   714→        if (*p == '\0') break;
   715→
   716→        /* Find end of component */
   717→        char *end = p;
   718→        while (*end != '/' && *end != '\0') end++;
   719→        int clen = (int)(end - p);
   720→
   721→        /* Determine if this is the last component */
   722→        char *next = end;
   723→        while (*next == '/') next++;
   724→        int is_last = (*next == '\0');
   725→
   726→        if (clen > DIRNAMELEN) return ERROR; /* Name too long */
   727→
   728→        if (is_last) {
   729→            /* Set parent and last component info */
   730→            if (parent_out) *parent_out = cur_inum;
   731→            if (last_name) {
   732→                memset(last_name, 0, DIRNAMELEN + 1);
   733→                memcpy(last_name, p, clen);
   734→            }
   735→            if (last_len) *last_len = clen;
   736→
   737→            /* Look up in current directory */
   738→            if (clen == 1 && p[0] == '.') {
   739→                return cur_inum; /* "." = current dir */
   740→            }
   741→            if (clen == 2 && p[0] == '.' && p[1] == '.') {
   742→                /* ".." = parent directory */
   743→                return dir_lookup(cur_inum, "..", 2);
   744→            }
   745→
   746→            int inum = dir_lookup(cur_inum, p, clen);
   747→            if (inum <= 0) return inum; /* 0 = not found, ERROR = error */
   748→
   749→            if (follow_last) {
   750→                struct inode *in = get_inode(inum);
   751→                if (!in) return ERROR;
   752→                if (in->type == INODE_SYMLINK) {
   753→                    char link_buf[MAXPATHNAMELEN + 1];
   754→                    if (read_symlink_target(inum, link_buf, sizeof(link_buf)) == ERROR)
   755→                        return ERROR;
   756→                    /* Relative symlink: resolve from directory where symlink is found */
   757→                    int link_cwd = (link_buf[0] == '/') ? ROOTINODE : cur_inum;
   758→                    return resolve_path(link_buf, link_cwd, follow_last,
   759→                                       parent_out, last_name, last_len,
   760→                                       symlink_depth + 1);
   761→                }
   762→            }
   763→            return inum;
   764→
   765→        } else {
   766→            /* Non-last component: must resolve to a directory */
   767→            if (clen == 1 && p[0] == '.') {
   768→                /* Stay at current dir */
   769→                p = end;
   770→                continue;
   771→            }
   772→            if (clen == 2 && p[0] == '.' && p[1] == '.') {
   773→                int parent_inum = dir_lookup(cur_inum, "..", 2);
   774→                if (parent_inum <= 0) return parent_inum;
   775→                cur_inum = parent_inum;
   776→                p = end;
   777→                continue;
   778→            }
   779→
   780→            int inum = dir_lookup(cur_inum, p, clen);
   781→            if (inum == 0) return 0; /* Component not found */
   782→            if (inum == ERROR) return ERROR;
   783→
   784→            /* Follow symlinks for non-last components */
   785→            struct inode *in = get_inode(inum);
   786→            if (!in) return ERROR;
   787→
   788→            if (in->type == INODE_SYMLINK) {
   789→                char link_buf[MAXPATHNAMELEN + 1];
   790→                if (read_symlink_target(inum, link_buf, sizeof(link_buf)) == ERROR)
   791→                    return ERROR;
   792→                int link_cwd = (link_buf[0] == '/') ? ROOTINODE : cur_inum;
   793→                inum = resolve_path(link_buf, link_cwd, 1, 0, 0, 0, symlink_depth + 1);
   794→                if (inum <= 0) return inum;
   795→                in = get_inode(inum);
   796→                if (!in) return ERROR;
   797→            }
   798→
   799→            if (in->type != INODE_DIRECTORY) return ERROR;
   800→            cur_inum = inum;
   801→            p = end;
   802→        }
   803→    }
   804→
   805→    /* Reached end without last component (shouldn't happen due to normalization) */
   806→    if (parent_out) *parent_out = cur_inum;
   807→    return cur_inum;
   808→}
