   921→static void handle_read(int pid, struct yfs_msg *msg) {
   922→    int file_inum = msg->inum;
   923→    int reuse = msg->arg1;
   924→    int pos = msg->arg2;
   925→    int size = msg->arg3;
   926→
   927→    struct inode *in = get_inode(file_inum);
   928→    if (!in) { reply_error(pid); return; }
   929→    if (in->type == INODE_FREE) { reply_error(pid); return; }
   930→    if (in->reuse != reuse) { reply_error(pid); return; }
   931→    if (size < 0) { reply_error(pid); return; }
   932→
   933→    int file_size = in->size;
   934→    if (pos >= file_size || size == 0) {
   935→        reply_int(pid, 0);
   936→        return;
   937→    }
   938→
   939→    int to_read = size;
   940→    if (pos + to_read > file_size) to_read = file_size - pos;
   941→
   942→    int bytes_done = 0;
   943→    char *client_buf = (char *)msg->ptr;
   944→
   945→    while (bytes_done < to_read) {
   946→        int cur_pos = pos + bytes_done;
   947→        int block_idx = cur_pos / BLOCKSIZE;
   948→        int off_in_block = cur_pos % BLOCKSIZE;
   949→        int can_read = BLOCKSIZE - off_in_block;
   950→        if (bytes_done + can_read > to_read) can_read = to_read - bytes_done;
   951→
   952→        int blknum = get_file_block(file_inum, block_idx, 0);
   953→        if (blknum == ERROR) { reply_error(pid); return; }
   954→
   955→        if (blknum == 0) {
   956→            /* Hole: copy zeros */
   957→            char zero_buf[BLOCKSIZE];
   958→            memset(zero_buf, 0, can_read);
   959→            if (CopyTo(pid, client_buf + bytes_done, zero_buf, can_read) != 0) {
   960→                reply_error(pid); return;
   961→            }
   962→        } else {
   963→            struct block_entry *be = get_block(blknum);
   964→            if (CopyTo(pid, client_buf + bytes_done, be->data + off_in_block, can_read) != 0) {
   965→                reply_error(pid); return;
   966→            }
   967→        }
   968→        bytes_done += can_read;
   969→    }
   970→
   971→    reply_int(pid, bytes_done);
   972→}
