  1202→/* ---- ReadLink ---- */
  1203→static void handle_readlink(int pid, struct yfs_msg2 *msg) {
  1204→    char path[MAXPATHNAMELEN];
  1205→    int plen = msg->arg1;
  1206→    int buflen = msg->arg2;
  1207→
  1208→    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
  1209→    if (CopyFrom(pid, path, msg->ptr1, plen) != 0) { reply_error(pid); return; }
  1210→    path[plen - 1] = '\0';
  1211→
  1212→    /* Resolve path WITHOUT following last symlink */
  1213→    int inum = resolve_path(path, msg->inum, 0, 0, 0, 0, 0);
  1214→    if (inum <= 0) { reply_error(pid); return; }
  1215→
  1216→    struct inode *in = get_inode(inum);
  1217→    if (!in || in->type != INODE_SYMLINK) { reply_error(pid); return; }
  1218→
  1219→    int sym_size = in->size;
  1220→    int to_copy = (sym_size < buflen) ? sym_size : buflen;
  1221→
  1222→    /* Copy symlink content to client's buffer */
  1223→    int bytes_done = 0;
  1224→    char *client_buf = (char *)msg->ptr2;
  1225→
  1226→    while (bytes_done < to_copy) {
  1227→        int block_idx = bytes_done / BLOCKSIZE;
  1228→        int off_in_block = bytes_done % BLOCKSIZE;
  1229→        int can_read = BLOCKSIZE - off_in_block;
  1230→        if (bytes_done + can_read > to_copy) can_read = to_copy - bytes_done;
  1231→
  1232→        int blknum = get_file_block(inum, block_idx, 0);
  1233→        if (blknum == ERROR) { reply_error(pid); return; }
  1234→
  1235→        if (blknum == 0) {
  1236→            char zeros[BLOCKSIZE];
  1237→            memset(zeros, 0, can_read);
  1238→            if (CopyTo(pid, client_buf + bytes_done, zeros, can_read) != 0) {
  1239→                reply_error(pid); return;
  1240→            }
  1241→        } else {
  1242→            struct block_entry *be = get_block(blknum);
  1243→            if (CopyTo(pid, client_buf + bytes_done, be->data + off_in_block, can_read) != 0) {
  1244→                reply_error(pid); return;
  1245→            }
  1246→        }
  1247→        bytes_done += can_read;
  1248→    }
  1249→
  1250→    reply_int(pid, to_copy);
  1251→}
