  1262→    path[plen - 1] = '\0';
  1263→
  1264→    int inum = resolve_path(path, msg->inum, 0, &parent_inum, last_name, &last_len, 0);
  1265→    if (inum != 0) { reply_error(pid); return; } /* Already exists */
  1266→    if (parent_inum <= 0) { reply_error(pid); return; }
  1267→    if (last_len == 0) { reply_error(pid); return; }
  1268→    /* Can't create "." or ".." as new dir */
  1269→    if (last_len == 1 && last_name[0] == '.') { reply_error(pid); return; }
  1270→    if (last_len == 2 && last_name[0] == '.' && last_name[1] == '.') { reply_error(pid); return; }
