  1275→
  1276→    struct inode *in = get_inode(new_inum);
  1277→    in->type = INODE_DIRECTORY;
  1278→    in->nlink = 2; /* "." and parent's entry */
  1279→    in->size = 0;
  1280→    memset(in->direct, 0, sizeof(in->direct));
  1281→    in->indirect = 0;
  1282→    mark_inode_dirty(new_inum);
