  1286→        release_inode(new_inum);
  1287→        reply_error(pid); return;
  1288→    }
  1289→
  1290→    /* Add ".." entry (points to parent) */
  1291→    if (dir_add_entry(new_inum, "..", 2, parent_inum) != 0) {
  1292→        free_file_blocks(new_inum);
  1293→        release_inode(new_inum);
  1294→        reply_error(pid); return;
  1295→    }
  1296→
  1297→    /* Add entry in parent directory */
  1298→    if (dir_add_entry(parent_inum, last_name, last_len, new_inum) != 0) {
