  1415→/* ===== Initialization ===== */
  1416→
  1417→static void init_fs(void) {
  1418→    int i;
  1419→    char super_buf[BLOCKSIZE];
  1420→
  1421→    /* Initialize block cache */
  1422→    bcache_used = 0;
  1423→    blru_head = blru_tail = 0;
  1424→    memset(bhash, 0, sizeof(bhash));
  1425→    for (i = 0; i < BLOCK_CACHESIZE; i++) {
  1426→        bcache[i].blocknum = -1;
  1427→        bcache[i].dirty = 0;
  1428→        bcache[i].lru_prev = bcache[i].lru_next = bcache[i].hash_next = 0;
  1429→    }
  1430→
  1431→    /* Initialize inode cache */
  1432→    icache_used = 0;
  1433→    ilru_head = ilru_tail = 0;
  1434→    memset(ihash, 0, sizeof(ihash));
  1435→    for (i = 0; i < INODE_CACHESIZE; i++) {
  1436→        icache[i].inum = -1;
  1437→        icache[i].dirty = 0;
  1438→        icache[i].lru_prev = icache[i].lru_next = icache[i].hash_next = 0;
  1439→    }
  1440→
  1441→    /* Read superblock directly (bypass cache for initial read) */
  1442→    ReadSector(1, super_buf);
  1443→    struct fs_header *hdr = (struct fs_header *)super_buf;
  1444→    g_num_blocks = hdr->num_blocks;
  1445→    g_num_inodes = hdr->num_inodes;
  1446→    g_first_data_block = 1 + (g_num_inodes + 1 + INODES_PER_BLOCK - 1) / INODES_PER_BLOCK;
  1447→
  1448→    TracePrintf(0, "YFS init: num_blocks=%d, num_inodes=%d, first_data=%d\n",
  1449→                g_num_blocks, g_num_inodes, g_first_data_block);
  1450→
  1451→    /* Track which data blocks are in use */
  1452→    static int block_used[NUMBLOCKS];
  1453→    memset(block_used, 0, sizeof(block_used));
  1454→    /* Mark boot/inode blocks as used */
  1455→    for (i = 0; i < g_first_data_block; i++) block_used[i] = 1;
  1456→
  1457→    /* Scan all inodes to build free lists */
  1458→    nfree_inodes = 0;
  1459→    for (i = 1; i <= g_num_inodes; i++) {
  1460→        struct inode *in = get_inode(i);
  1461→        if (in->type == INODE_FREE) {
  1462→            free_inodes[nfree_inodes++] = i;
  1463→        } else {
  1464→            int j;
  1465→            for (j = 0; j < NUM_DIRECT; j++) {
  1466→                if (in->direct[j] != 0 && in->direct[j] < g_num_blocks)
  1467→                    block_used[in->direct[j]] = 1;
  1468→            }
  1469→            if (in->indirect != 0 && in->indirect < g_num_blocks) {
  1470→                block_used[in->indirect] = 1;
  1471→                struct block_entry *ibe = get_block(in->indirect);
  1472→                int *tbl = (int *)ibe->data;
  1473→                int k;
  1474→                for (k = 0; k < INDIRECT_PER_BLOCK; k++) {
  1475→                    if (tbl[k] != 0 && tbl[k] < g_num_blocks)
  1476→                        block_used[tbl[k]] = 1;
  1477→                }
  1478→            }
  1479→        }
  1480→    }
  1481→
  1482→    /* Build free block stack */
  1483→    nfree_blocks = 0;
  1484→    for (i = g_first_data_block; i < g_num_blocks; i++) {
  1485→        if (!block_used[i]) free_blocks[nfree_blocks++] = i;
  1486→    }
  1487→
  1488→    TracePrintf(0, "YFS: %d free blocks, %d free inodes\n", nfree_blocks, nfree_inodes);
  1489→}
