    13→/* ===== Message protocol ===== */
    14→
    15→/*
    16→ * One-pointer message: 4+4+4+4+4+4+8 = 32 bytes
    17→ * Used for: Open, Create, Read, Write, Seek, Unlink, MkDir, RmDir, ChDir, Sync, Shutdown
    18→ */
    19→struct yfs_msg {
    20→    int type;   /* operation type */
    21→    int inum;   /* cwd_inum (path ops) or file_inum (fd ops) */
    22→    int arg1;   /* pathlen, reuse, or 0 */
    23→    int arg2;   /* pos or 0 */
    24→    int arg3;   /* size, whence, or 0 */
    25→    int arg4;   /* offset or 0 */
    26→    void *ptr;  /* pathname or data buffer */
    27→};
    28→
    29→/*
    30→ * Two-pointer message: 4+4+4+4+8+8 = 32 bytes
    31→ * Used for: Link, SymLink, ReadLink, Stat
    32→ */
    33→struct yfs_msg2 {
    34→    int type;   /* operation type */
    35→    int inum;   /* cwd_inum */
    36→    int arg1;   /* len1 (first path length) */
    37→    int arg2;   /* len2 (second path / buf length) */
    38→    void *ptr1; /* first path */
    39→    void *ptr2; /* second path or result buffer */
    40→};
    41→
    42→/* Operation type codes */
    43→#define OP_OPEN     1
    44→#define OP_CREATE   2
    45→#define OP_READ     3
    46→#define OP_WRITE    4
    47→#define OP_SEEK     5
    48→#define OP_LINK     6
