    50→#define OP_SYMLINK  8
    51→#define OP_READLINK 9
    52→#define OP_MKDIR    10
    53→#define OP_RMDIR    11
    54→#define OP_CHDIR    12
    55→#define OP_STAT     13
    56→#define OP_SYNC     14
    57→#define OP_SHUTDOWN 15
