    59→/* ===== File descriptor table ===== */
    60→
    61→struct fd_entry {
    62→    int used;
    63→    int inum;
    64→    int reuse;
    65→    int pos;
    66→    int is_dir; /* 1 if directory (write not allowed) */
    67→};
    68→
    69→static struct fd_entry fd_table[MAX_OPEN_FILES];
    70→static int cwd_inum = ROOTINODE;
    71→
    72→/* Find lowest available fd slot */
    73→static int find_free_fd(void) {
    74→    int i;
    75→    for (i = 0; i < MAX_OPEN_FILES; i++) {
    76→        if (!fd_table[i].used) return i;
    77→    }
    78→    return ERROR;
    79→}
    80→
    81→/* Validate fd and return entry pointer */
    82→static struct fd_entry *get_fd(int fd) {
    83→    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].used) return (void *)0;
    84→    return &fd_table[fd];
    85→}
