    89→int Open(char *pathname) {
    90→    struct yfs_msg msg;
    91→    int fd, plen;
    92→
    93→    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    94→    plen = strlen(pathname) + 1;
    95→    if (plen > MAXPATHNAMELEN) return ERROR;
    96→
    97→    fd = find_free_fd();
    98→    if (fd == ERROR) return ERROR;
    99→
   100→    msg.type = OP_OPEN;
   101→    msg.inum = cwd_inum;
   102→    msg.arg1 = plen;
   103→    msg.arg2 = 0;
   104→    msg.arg3 = 0;
   105→    msg.arg4 = 0;
   106→    msg.ptr = pathname;
   107→
   108→    Send(&msg, -FILE_SERVER);
   109→    /* Reply: inum=file_inum (or ERROR), arg1=reuse, arg2=inode_type */
   110→    if (msg.inum == ERROR) return ERROR;
