   112→    fd_table[fd].used = 1;
   113→    fd_table[fd].inum = msg.inum;
   114→    fd_table[fd].reuse = msg.arg1;
   115→    fd_table[fd].pos = 0;
   116→    fd_table[fd].is_dir = (msg.arg2 == INODE_DIRECTORY);
   117→    return fd;
   118→}
