   158→int Read(int fd, void *buf, int size) {
   159→    struct yfs_msg msg;
   160→    struct fd_entry *entry;
   161→
   162→    entry = get_fd(fd);
   163→    if (!entry) return ERROR;
   164→    if (buf == NULL || size < 0) return ERROR;
   165→    if (size == 0) return 0;
   166→
   167→    msg.type = OP_READ;
   168→    msg.inum = entry->inum;
   169→    msg.arg1 = entry->reuse;
   170→    msg.arg2 = entry->pos;
   171→    msg.arg3 = size;
   172→    msg.arg4 = 0;
   173→    msg.ptr = buf;
   174→
   175→    Send(&msg, -FILE_SERVER);
   176→    /* Reply: inum=bytes_read (or ERROR) */
   177→    if (msg.inum == ERROR) return ERROR;
   178→    entry->pos += msg.inum;
   179→    return msg.inum;
   180→}
   181→
   182→int Write(int fd, void *buf, int size) {
   183→    struct yfs_msg msg;
   184→    struct fd_entry *entry;
   185→
   186→    entry = get_fd(fd);
   187→    if (!entry) return ERROR;
   188→    if (entry->is_dir) return ERROR; /* Can't write to directory */
   189→    if (buf == NULL || size < 0) return ERROR;
   190→    if (size == 0) return 0;
   191→
   192→    msg.type = OP_WRITE;
   193→    msg.inum = entry->inum;
   194→    msg.arg1 = entry->reuse;
   195→    msg.arg2 = entry->pos;
   196→    msg.arg3 = size;
   197→    msg.arg4 = 0;
   198→    msg.ptr = buf;
   199→
   200→    Send(&msg, -FILE_SERVER);
   201→    /* Reply: inum=bytes_written (or ERROR) */
   202→    if (msg.inum == ERROR) return ERROR;
   203→    entry->pos += msg.inum;
   204→    return msg.inum;
   205→}
