   207→int Seek(int fd, int offset, int whence) {
   208→    struct yfs_msg msg;
   209→    struct fd_entry *entry;
   210→
   211→    entry = get_fd(fd);
   212→    if (!entry) return ERROR;
   213→
   214→    msg.type = OP_SEEK;
   215→    msg.inum = entry->inum;
   216→    msg.arg1 = entry->reuse;
   217→    msg.arg2 = entry->pos;
   218→    msg.arg3 = whence;
   219→    msg.arg4 = offset;
   220→    msg.ptr = (void *)0;
   221→
   222→    Send(&msg, -FILE_SERVER);
   223→    /* Reply: inum=new_pos (or ERROR) */
   224→    if (msg.inum == ERROR) return ERROR;
   225→    entry->pos = msg.inum;
   226→    return msg.inum;
   227→}
