   273→    /* Insert into hash and LRU */
   274→    slot->hash_next = ihash[h];
   275→    ihash[h] = slot;
   276→    ilru_push_front(slot);
   277→
   278→    return &slot->data;
   279→}
   280→
   281→static void mark_inode_dirty(int inum) {
   282→    int h = inum % INODE_HASH_SIZE;
   283→    struct inode_entry *e = ihash[h];
   284→    while (e) {
   285→        if (e->inum == inum) {
   286→            e->dirty = 1;
   287→            return;
   288→        }
   289→        e = e->hash_next;
   290→    }
   291→}
   292→
   293→/* ===== Cache sync ===== */
   294→
   295→static void sync_caches(void) {
   296→    int i;
   297→    /* Phase 1: write all dirty inodes to block cache */
   298→    for (i = 0; i < INODE_CACHESIZE; i++) {
   299→        if (icache[i].inum != -1 && icache[i].dirty) {
   300→            inode_writeback(&icache[i]);
   301→        }
   302→    }
   303→    /* Phase 2: write all dirty blocks to disk */
   304→    for (i = 0; i < BLOCK_CACHESIZE; i++) {
   305→        if (bcache[i].blocknum != -1 && bcache[i].dirty) {
   306→            WriteSector(bcache[i].blocknum, bcache[i].data);
   307→            bcache[i].dirty = 0;
   308→        }
   309→    }
   310→}
   311→
   312→/* ===== Alloc/Free ===== */
   313→
   314→static int alloc_block(void) {
   315→    if (nfree_blocks == 0) return ERROR;
   316→    return free_blocks[--nfree_blocks];
   317→}
   318→
   319→static void release_block(int blknum) {
   320→    if (blknum <= 0 || blknum >= g_num_blocks) return;
   321→    free_blocks[nfree_blocks++] = blknum;
   322→    /* Also remove from cache and mark clean (invalidate) */
   323→    int h = blknum % BLOCK_HASH_SIZE;
   324→    struct block_entry *e = bhash[h];
   325→    while (e) {
   326→        if (e->blocknum == blknum) {
   327→            e->dirty = 0; /* Don't write freed block to disk */
   328→            break;
   329→        }
   330→        e = e->hash_next;
   331→    }
   332→}
   333→
   334→static int alloc_inode(void) {
   335→    if (nfree_inodes == 0) return ERROR;
   336→    int inum = free_inodes[--nfree_inodes];
   337→    struct inode *in = get_inode(inum);
   338→    in->reuse++;
   339→    mark_inode_dirty(inum);
   340→    return inum;
   341→}
   342→
   343→static void release_inode(int inum) {
   344→    struct inode *in = get_inode(inum);
   345→    in->type = INODE_FREE;
   346→    in->nlink = 0;
   347→    in->size = 0;
   348→    memset(in->direct, 0, sizeof(in->direct));
   349→    in->indirect = 0;
   350→    mark_inode_dirty(inum);
   351→    free_inodes[nfree_inodes++] = inum;
   352→}
   353→
   354→/* ===== File block access ===== */
   355→
   356→/*
   357→ * Get the disk block number for a given block index in a file.
   358→ * If create_if_missing=1, allocate a new block if needed (and mark inode dirty).
   359→ * Returns block number (0 = hole), or ERROR on failure.
   360→ */
   361→static int get_file_block(int inum, int block_idx, int create_if_missing) {
   362→    struct inode *in = get_inode(inum);
   363→
   364→    if (block_idx < NUM_DIRECT) {
   365→        int blknum = in->direct[block_idx];
   366→        if (blknum == 0 && create_if_missing) {
   367→            int newblk = alloc_block();
   368→            if (newblk == ERROR) return ERROR;
   369→            /* Zero-fill the new block */
   370→            struct block_entry *be = get_block(newblk);
   371→            memset(be->data, 0, BLOCKSIZE);
   372→            be->dirty = 1;
   373→            /* Re-fetch inode (get_block might have evicted it from block cache,
   374→               but the inode cache is separate so pointer is still valid) */
   375→            in = get_inode(inum);
   376→            in->direct[block_idx] = newblk;
   377→            mark_inode_dirty(inum);
   378→            return newblk;
   379→        }
   380→        return blknum; /* 0 means hole */
   381→    }
   382→
   383→    /* Indirect block */
   384→    int indirect_idx = block_idx - NUM_DIRECT;
   385→    if (indirect_idx >= INDIRECT_PER_BLOCK) return ERROR; /* File too large */
   386→
   387→    in = get_inode(inum);
   388→    if (in->indirect == 0) {
   389→        if (!create_if_missing) return 0; /* hole */
   390→        int iblk = alloc_block();
   391→        if (iblk == ERROR) return ERROR;
   392→        /* Zero-fill indirect block */
   393→        struct block_entry *ibe = get_block(iblk);
   394→        memset(ibe->data, 0, BLOCKSIZE);
   395→        ibe->dirty = 1;
   396→        in = get_inode(inum);
   397→        in->indirect = iblk;
   398→        mark_inode_dirty(inum);
   399→    }
   400→
   401→    int indirect_blk = get_inode(inum)->indirect;
   402→    {
   403→        struct block_entry *ibe = get_block(indirect_blk);
   404→        int *tbl = (int *)ibe->data;
   405→        int blknum = tbl[indirect_idx];
   406→        if (blknum != 0 || !create_if_missing) return blknum;
   407→    }
   408→
   409→    /* Allocate new data block */
   410→    int newblk = alloc_block();
   411→    if (newblk == ERROR) return ERROR;
   412→    {
   413→        struct block_entry *be = get_block(newblk);
   414→        memset(be->data, 0, BLOCKSIZE);
   415→        be->dirty = 1;
   416→    }
   417→    /* Re-fetch indirect block (get_block might have moved things around) */
   418→    {
   419→        struct block_entry *ibe = get_block(indirect_blk);
   420→        ((int *)ibe->data)[indirect_idx] = newblk;
   421→        ibe->dirty = 1;
   422→    }
   423→    return newblk;
   424→}
   425→
   426→/*
   427→ * Free all data blocks of a file (direct and indirect).
   428→ */
   429→static void free_file_blocks(int inum) {
   430→    struct inode *in = get_inode(inum);
   431→    int i;
   432→
   433→    /* Free direct blocks */
   434→    for (i = 0; i < NUM_DIRECT; i++) {
   435→        if (in->direct[i] != 0) {
   436→            release_block(in->direct[i]);
   437→            in->direct[i] = 0;
   438→        }
   439→    }
   440→    /* Free indirect block's entries */
   441→    if (in->indirect != 0) {
   442→        struct block_entry *ibe = get_block(in->indirect);
   443→        int *tbl = (int *)ibe->data;
   444→        for (i = 0; i < INDIRECT_PER_BLOCK; i++) {
   445→            if (tbl[i] != 0) {
   446→                release_block(tbl[i]);
   447→                tbl[i] = 0;
   448→            }
   449→        }
   450→        ibe->dirty = 0; /* Don't need to write freed indirect block */
   451→        release_block(in->indirect);
   452→        in = get_inode(inum); /* Re-fetch after block ops */
   453→        in->indirect = 0;
   454→    }
   455→    in = get_inode(inum);
   456→    in->size = 0;
   457→    memset(in->direct, 0, sizeof(in->direct));
   458→    in->indirect = 0;
   459→    mark_inode_dirty(inum);
   460→}
   461→
   462→/* ===== Directory operations ===== */
   463→
   464→/*
   465→ * Name comparison for directory entries.
   466→ * dir_name: up to DIRNAMELEN bytes (not null-terminated if exactly DIRNAMELEN)
   467→ * name: the name to search for
   468→ * namelen: length of name (not including null terminator)
   469→ */
   470→static int name_match(const char *dir_name, const char *name, int namelen) {
   471→    if (namelen > DIRNAMELEN) return 0;
   472→    if (memcmp(dir_name, name, namelen) != 0) return 0;
   473→    if (namelen < DIRNAMELEN && dir_name[namelen] != '\0') return 0;
   474→    return 1;
   475→}
