     1→/*
     2→ *  Create an empty Yalnix file system on the Yalnix DISK.
     3→ *
     4→ *  This is a Unix program (not a Yalnix program).  It creates a Yalnix
     5→ *  file system in the Unix file named "DISK".  This file is then used
     6→ *  by the Yalnix hardware simulation as the Yalnix disk device.  You
     7→ *  can write other Unix programs or use existing Unix tools to create
     8→ *  "interesting" DISK contents to test your server on or to examine
     9→ *  the "raw" contents of your file system on disk.  For example,
    10→ *  running "od -X DISK" or "od -c DISK" under Unix can be useful ways
    11→ *  to get a quick look at the DISK contents.
    12→ *
    13→ *  Usage: mkyfs [num_inodes]
    14→ *
    15→ *  The default number of inodes if num_inodes is not specified is
    16→ *  given by the DEFAULT_NUM_INODES constant below.
    17→ *
    18→ *  RUN THIS COMMAND AS A UNIX PROGRAM, NOT AS A YALNIX PROGRAM.
    19→ */
    20→
    21→#include <fcntl.h>
    22→#include <stdio.h>
    23→#include <string.h>
    24→#include <stdlib.h>
    25→#include <unistd.h>
    26→
    27→#include <comp421/filesystem.h>
    28→
    29→#define	INODES_PER_BLOCK	(BLOCKSIZE/INODESIZE)
    30→
    31→#define DISK_FILE_NAME		"DISK"
    32→#define DEFAULT_NUM_INODES	(6 * INODES_PER_BLOCK - 1)
    33→
    34→union {
    35→    struct fs_header hdr;
    36→    struct inode inode[INODES_PER_BLOCK];
    37→    char buf[BLOCKSIZE];
    38→} block;
    39→
    40→int
    41→main(int argc, char **argv)
    42→{
    43→    int disk;
    44→    int num_inodes = DEFAULT_NUM_INODES;
    45→    int i;
    46→    struct inode *inodes;
    47→    int inodes_size;
    48→    struct dir_entry root[2];
    49→
    50→    if (argc > 1) {
    51→	if (sscanf(argv[1], "%d", &num_inodes) != 1) {
    52→	    fprintf(stderr, "usage: mkyfs [num_inodes]\n");
    53→	    exit(1);
    54→	}
    55→    }
    56→
    57→    if ((disk = creat(DISK_FILE_NAME, 0666)) < 0) {
    58→	perror(DISK_FILE_NAME);
    59→	exit(1);
    60→    }
    61→
    62→    lseek(disk, BLOCKSIZE, 0);
    63→
    64→    inodes_size = (num_inodes + 1) * INODESIZE;
    65→    /* force rounded up to BLOCKSIZE multiple */
    66→    inodes_size = (inodes_size + BLOCKSIZE - 1) & ~(BLOCKSIZE - 1);
    67→    inodes = (struct inode *)malloc(inodes_size);
    68→
    69→    ((struct fs_header *)inodes)->num_blocks = NUMSECTORS;
    70→    ((struct fs_header *)inodes)->num_inodes = num_inodes;
    71→
    72→    inodes[1].type = INODE_DIRECTORY;
    73→    inodes[1].nlink = 2;
    74→    inodes[1].reuse = 1;
    75→    inodes[1].size = 2 * sizeof(struct dir_entry);
    76→    inodes[1].direct[0] = (inodes_size / BLOCKSIZE) + 1;
    77→
    78→    for (i = 2; i <= num_inodes; i++) {
    79→	inodes[i].type = INODE_FREE;
    80→	/* all other fields are automatically 0 */
    81→    }
    82→
    83→    if (write(disk, inodes, inodes_size) != inodes_size) {
    84→	perror("write inodes");
    85→	unlink(DISK_FILE_NAME);
    86→	exit(1);
    87→    }
    88→
    89→    memset((void *)root, '\0', sizeof(root));
    90→    root[0].inum = ROOTINODE;
    91→    root[0].name[0] = '.';
    92→    root[1].inum = ROOTINODE;
    93→    root[1].name[0] = '.';
    94→    root[1].name[1] = '.';
    95→
    96→    if (write(disk, root, sizeof(root)) != sizeof(root)) {
    97→	perror("write root");
    98→	unlink(DISK_FILE_NAME);
    99→	exit(1);
   100→    }
   101→
   102→    /*
   103→     *  Seek to the last block of the DISK and write it full of zeros.
   104→     *  In Unix, this leaves a "hole" in the file, which will act
   105→     *  exactly as if it had been written full of zeros.  When reading
   106→     *  from this space skipped over here, Unix will read it as all
   107→     *  zeros.  By making this a hole, it is faster to run mkyfs,
   108→     *  and it saves real Unix disk space since a hole doesn't consume
   109→     *  physical disk blocks.
   110→     */
   111→    lseek(disk, BLOCKSIZE * (NUMSECTORS - 1), 0);
   112→    memset((void *)&block, '\0', BLOCKSIZE);
   113→    if (write(disk, &block, BLOCKSIZE) != BLOCKSIZE) {
   114→	perror("write last zero");
   115→	unlink(DISK_FILE_NAME);
   116→	exit(1);
   117→    }
   118→
   119→    exit(0);
   120→}
