   129→	ret = Write(fd, buf, 16);
   130→	assert("Wrote to directory\n", ret == ERROR);
   131→	Close(fd);
   132→
   133→	fd = Open("/");
   134→	ret = Read(fd, buf, 16);
   135→	assert("Read wrong number of bytes: / dir\n", ret == 16);
   136→	ret = Write(fd, buf, 16);
   137→	assert("Wrote to directory\n", ret == ERROR);
   138→	Close(fd);
   139→
