   142→	fd = Open(NULL);
   143→	assert("Opened null file\n", fd == ERROR);
   144→	ret = Read(fd, buf, 16);
   145→	assert("Read null file\n", ret == ERROR);
   146→	ret = Write(fd, buf, 16);
   147→	assert("Wrote null file\n", ret == ERROR);
