   162→
   163→	ret = MkDir("c");
   164→	ret = Stat("c", &mystat);
   165→	assert("Stats failed on c", ret == 0 && mystat.inum == 45 && mystat.type == INODE_DIRECTORY && mystat.size == 64 && mystat.nlink == 2);
   166→
   167→	ret = MkDir("c/d");
   168→	ret = Stat("c/d", &mystat);
   169→	assert("Stats failed on c/d", ret == 0 && mystat.inum == 44 && mystat.type == INODE_DIRECTORY && mystat.size == 64 && mystat.nlink == 2);
   170→
   171→	ret = Stat("f", &mystat);
   172→	assert("Stats failed on f", ret == ERROR);
   173→
   174→	ret = Sync();
